{
  "functions": [
    {
      "name": "多模型智能视频生成",
      "description": "集成多种先进AI图像与视频生成模型，智能组合最优模型方案，自动完成视频创作。"
    },
    {
      "name": "自动剪辑与高光提取",
      "description": "可将长视频（如25分钟访谈）自动拆分为多个适合社交媒体传播的短视频片段，提升内容传播效率。"
    },
    {
      "name": "动画故事生成",
      "description": "用户只需输入一句创意，CrePal即可自动生成包含脚本、分镜、配音和音效的完整动画短片。"
    },
    {
      "name": "智能脚本与字幕生成",
      "description": "根据主题和关键词自动生成流畅的旁白脚本，并为视频内容智能添加多语言字幕，支持个性化调整。"
    },
    {
      "name": "一键式视频渲染与社媒优化",
      "description": "自动将脚本、图片、音乐等素材组合成完整视频，支持多种输出格式，并针对不同平台（如YouTube、TikTok）自动优化尺寸和元数据。"
    }
  ],
  "roles": [
    {
      "name": "内容创作者/自媒体",
      "description": "快速将长视频、直播、Vlog等内容高效拆分、剪辑、加字幕，批量生成短视频用于多平台分发。"
    },
    {
      "name": "品牌/电商",
      "description": "上传产品图和文案，自动生成9:16竖版广告视频，统一品牌视觉，适配抖音、快手等平台。"
    },
    {
      "name": "教育/培训",
      "description": "输入课程大纲，AI自动生成动画预告片、教学短片，展示师资与成果。"
    },
    {
      "name": "影视/MCN机构",
      "description": "批量生成电影预告、剧集高光，自动识别爆点台词与动作，支持横竖双画幅。"
    },
    {
      "name": "企业市场/知识管理",
      "description": "企业内部培训视频自动加字幕、降噪、分段，一键归档至知识库。"
    }
  ],
  "features": [
    {
      "name": "全流程自动化",
      "description": "从脚本、分镜、配音、剪辑到渲染、字幕、格式优化全部AI自动完成。"
    },
    {
      "name": "多行业模板与案例库",
      "description": "内置丰富行业案例和风格模板，支持一键复用。"
    },
    {
      "name": "云端素材管理",
      "description": "支持Google账号快捷登录与云端素材管理。"
    },
    {
      "name": "多格式输出",
      "description": "支持多种主流视频格式导出，适配不同平台需求。"
    }
  ],
  "scenarios": [
    {
      "name": "Vlog/直播高光拆条",
      "description": "将30分钟Vlog或直播回放一键拆分为10条15秒高光，自动加字幕、花字和BGM，3分钟完成日更。"
    },
    {
      "name": "品牌广告视频生成",
      "description": "上传产品图+卖点文案，自动生成竖版广告视频，适配主流短视频平台。"
    },
    {
      "name": "教育动画短片制作",
      "description": "输入课程大纲，AI生成30秒动画预告片，展示教学亮点。"
    },
    {
      "name": "影视剧高光批量生成",
      "description": "上传剧集内容，自动识别高光片段，批量生成短视频用于宣传。"
    },
    {
      "name": "企业培训视频归档",
      "description": "企业培训视频自动加字幕、降噪、分段，一键归档至知识库。"
    }
  ],
  "pricing_plan": [
    {
      "name": "内测/预约制",
      "description": "目前处于私测阶段，需加入候补名单，具体定价与套餐待官方公布。"
    }
  ],
  "usage": [
    {
      "name": "自动剪辑与高光提取",
      "description": "1. 访问CrePal官网并注册；2. 上传长视频内容；3. 选择自动拆条任务；4. AI自动剪辑并生成短视频片段；5. 预览、调整后下载或一键分发。"
    },
    {
      "name": "动画故事生成",
      "description": "1. 进入动画创作任务；2. 输入一句创意或脚本；3. 选择风格模板和参数；4. AI自动生成动画短片，支持预览和微调。"
    }
  ],
  "questions": [
    {
      "name": "CrePal支持哪些视频类型？",
      "description": "支持长视频拆条、动画短片、广告视频、教育短片、影视高光等多种类型。"
    },
    {
      "name": "是否支持多平台优化？",
      "description": "支持针对YouTube、TikTok等主流平台自动优化视频尺寸、格式和元数据。"
    },
    {
      "name": "如何参与内测？",
      "description": "目前需加入官网候补名单，等待官方邀请参与私测。"
    },
    {
      "name": "生成视频是否可商用？",
      "description": "需关注官方后续授权与定价政策，建议确保上传素材拥有合法版权。"
    }
  ]
}

